+    #[allow(clippy::too_many_arguments)]
+    fn try_execute_precompiled_prepared_update_delete_autocommit_direct_simple_fast(
+        &self,
+        execution_cx: &Cx,
+        stmt: &PreparedStatement<'_>,
+        kind: PreparedDmlKind,
+        rollback_on_constraint_violation: bool,
+        preserve_prior_changes_on_constraint_violation: bool,
+        skip_statement_savepoint_in_explicit_txn: bool,
+        params: Option<&[SqliteValue]>,
+    ) -> Option<Result<usize>> {
+        if self.in_transaction.get()
+            || self.active_txn.borrow().is_some()
+            || !skip_statement_savepoint_in_explicit_txn
+            || rollback_on_constraint_violation
+        {
+            return None;
+        }
+
+        let fast_path = stmt.prepared_update_delete_fast_path()?;
+        let table_name = fast_path.table_name.as_str();
+        let has_direct_shape = match kind {
+            PreparedDmlKind::Update => fast_path.direct_simple_update.is_some(),
+            PreparedDmlKind::Delete => fast_path.direct_simple_delete.is_some(),
+            PreparedDmlKind::Insert => false,
+        };
+        if !has_direct_shape {
+            return None;
+        }
+
+        let was_auto = match self.ensure_autocommit_txn_with_publication_hint(execution_cx, None) {
+            Ok(was_auto) => was_auto,
+            Err(error) => return Some(Err(error)),
+        };
+        if !was_auto {
+            return Some(Err(FrankenError::internal(
+                "autocommit direct UPDATE/DELETE entered non-autocommit transaction",
+            )));
+        }
+
+        self.txn_metrics_note_write();
+        let execute_body_start = hot_path_profile_enabled().then(Instant::now);
+        let result = match kind {
+            PreparedDmlKind::Update => {
+                let direct = fast_path.direct_simple_update.as_ref()?;
+                if hot_path_profile_enabled() {
+                    FSQLITE_PREPARED_DIRECT_UPDATE_EXECUTIONS.fetch_add(1, AtomicOrdering::Relaxed);
+                }
+                self.execute_prepared_direct_simple_update(execution_cx, direct, params)
+            }
+            PreparedDmlKind::Delete => {
+                let direct = fast_path.direct_simple_delete.as_ref()?;
+                if hot_path_profile_enabled() {
+                    FSQLITE_PREPARED_DIRECT_DELETE_EXECUTIONS.fetch_add(1, AtomicOrdering::Relaxed);
+                }
+                self.execute_prepared_direct_simple_delete(execution_cx, direct, params)
+            }
+            PreparedDmlKind::Insert => return None,
+        };
+        record_hot_path_duration(&FSQLITE_EXECUTE_BODY_TIME_NS, execute_body_start);
+
+        let result = match result {
+            Ok(affected) => {
+                self.record_statement_changes_without_sync(affected);
+                Ok(affected)
+            }
+            Err(error) => match self.maybe_rollback_transaction_for_conflict_action(
+                rollback_on_constraint_violation,
+                was_auto,
+                &error,
+            ) {
+                Ok(()) => Err(error),
+                Err(rollback_error) => Err(rollback_error),
+            },
+        };
+        let commit_autocommit_on_error = preserve_prior_changes_on_constraint_violation
+            && matches!(
+                result.as_ref(),
+                Err(error) if error_is_constraint_violation(error)
+            );
+        let ok = result.is_ok() || commit_autocommit_on_error;
+        let resolve_result = self.resolve_autocommit_txn_with_dirty_table_and_capture_and_cx(
+            was_auto,
+            ok,
+            Some(table_name),
+            false,
+            execution_cx,
+        );
+        Some(match resolve_result {
+            Ok(()) => result,
+            Err(error) => Err(error),
+        })
+    }
